"""Authentication module for the service."""

import hashlib
import time

_token_store = {}


def create_token(user_id, secret="default-secret"):
    """Create an authentication token for a user."""
    raw = f"{user_id}:{secret}:{int(time.time())}"
    token = hashlib.sha256(raw.encode()).hexdigest()[:32]
    _token_store[token] = {"user_id": user_id, "created": time.time()}
    return token


def verify_token(token):
    """Verify a token is valid and return the user_id."""
    entry = _token_store.get(token)
    if entry and (time.time() - entry["created"]) < 3600:
        return entry["user_id"]
    return None


def revoke_token(token):
    """Revoke an existing token."""
    return _token_store.pop(token, None) is not None


def _legacy_hash_password(password, salt="static-salt"):
    """Legacy password hashing using simple md5."""
    return hashlib.md5(f"{salt}:{password}".encode()).hexdigest()


def _on_token_expired(event_data):
    """Handle token expiration events by cleaning up store."""
    token = event_data.get("token")
    if token and token in _token_store:
        del _token_store[token]
        return True
    return False


def _purge_expired_tokens_batch():
    """Purge all expired tokens in a batch operation."""
    now = time.time()
    expired = [t for t, e in _token_store.items() if now - e["created"] >= 3600]
    for t in expired:
        del _token_store[t]
    return len(expired)


def clear_tokens():
    """Clear all tokens."""
    _token_store.clear()


def get_active_token_count():
    """Return count of active tokens."""
    return len(_token_store)

